import React from 'react';
import { motion } from 'framer-motion';

export default function StyleGuide() {
  const colors = [
    { name: 'Ivory', hex: 'bg-[#FFFFF0]' },
    { name: 'Royal Gold', hex: 'bg-[#D4AF37]' },
    { name: 'Deep Emerald', hex: 'bg-[#043927]' },
  ];

  return (
    <section className="py-24 bg-white text-center">
      <div className="max-w-4xl mx-auto px-6" data-aos="fade-up">
        <h2 className="font-serif text-5xl italic mb-6">Dress Code</h2>
        <p className="text-gray-500 tracking-widest text-xs uppercase mb-12">Theme: Royal Elegance</p>
        
        <div className="flex justify-center gap-6 mb-12">
          {colors.map((color, i) => (
            <div key={i} className="flex flex-col items-center">
              <div className={`${color.hex} w-16 h-16 rounded-full shadow-inner border border-gray-100 mb-2`}></div>
              <span className="text-[10px] uppercase tracking-tighter text-gray-400">{color.name}</span>
            </div>
          ))}
        </div>
        
        <p className="text-sm font-light leading-relaxed text-gray-500 max-w-md mx-auto italic">
          "We kindly request our guests to join us in our wedding colors to create a beautiful harmony in our photos."
        </p>
      </div>
    </section>
  );
}
